using ProductsApi.Models;

namespace ProductsApi.Services;

public sealed class InMemoryProductService : IProductService
{
    private readonly List<Product> _products = [];
    private int _nextId = 1;
    private readonly Lock _lock = new();

    public Task<IReadOnlyList<ProductResponse>> GetAllAsync(CancellationToken ct)
    {
        lock (_lock)
        {
            var results = _products.Select(MapToResponse).ToList();
            return Task.FromResult<IReadOnlyList<ProductResponse>>(results);
        }
    }

    public Task<ProductResponse?> GetByIdAsync(int id, CancellationToken ct)
    {
        lock (_lock)
        {
            var product = _products.FirstOrDefault(p => p.Id == id);
            return Task.FromResult(product is null ? null : MapToResponse(product));
        }
    }

    public Task<ProductResponse> CreateAsync(CreateProductRequest request, CancellationToken ct)
    {
        lock (_lock)
        {
            var product = new Product
            {
                Id = _nextId++,
                Name = request.Name,
                Price = request.Price,
                Category = request.Category,
                CreatedAt = DateTimeOffset.UtcNow
            };

            _products.Add(product);
            return Task.FromResult(MapToResponse(product));
        }
    }

    private static ProductResponse MapToResponse(Product p) =>
        new(p.Id, p.Name, p.Price, p.Category, p.CreatedAt);
}

